import{_ as r,o as a,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"G04 核心產品與競爭優勢 — 良維科技 (6290)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6290_良維/20260424/G04_核心產品與競爭優勢.md","filePath":"審計報告庫/經營審計/6290_良維/20260424/G04_核心產品與競爭優勢.md"}'),n={name:"審計報告庫/經營審計/6290_良維/20260424/G04_核心產品與競爭優勢.md"};function d(s,t,l,i,h,g){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="g04-核心產品與競爭優勢-—-良維科技-6290" tabindex="-1">G04 核心產品與競爭優勢 — 良維科技 (6290) <a class="header-anchor" href="#g04-核心產品與競爭優勢-—-良維科技-6290" aria-label="Permalink to &quot;G04 核心產品與競爭優勢 — 良維科技 (6290)&quot;">​</a></h1><p><strong>報告日期</strong>：2026-04-24 <strong>分析師</strong>：投資研究員 (Deep32Q L3) <strong>數據截止</strong>：2026-04-23</p><hr><h2 id="一、核心產品組合與營收結構" tabindex="-1">一、核心產品組合與營收結構 <a class="header-anchor" href="#一、核心產品組合與營收結構" aria-label="Permalink to &quot;一、核心產品組合與營收結構&quot;">​</a></h2><p>良維科技的核心產品線涵蓋四大類別，根據 2025 年營收比重分布如下：</p><table tabindex="0"><thead><tr><th>產品類別</th><th>營收佔比 (2025年)</th><th>核心功能</th><th>應用終端</th></tr></thead><tbody><tr><td>電源傳輸線組</td><td>90.99%</td><td>AC/DC 電力傳輸</td><td>AI 伺服器、資料中心、消費電子、家電</td></tr><tr><td>訊號傳輸線組</td><td>6.51%</td><td>高頻訊號傳遞</td><td>電腦周邊、通訊設備、車用電子</td></tr><tr><td>充電器轉接頭</td><td>2.22%</td><td>電源轉換適配</td><td>3C 產品、電動車充電</td></tr><tr><td>其他</td><td>0.28%</td><td>客製化零組件</td><td>特殊工業應用</td></tr></tbody></table><p>（資料來源：玉山證券個股頁面、法說會簡報）</p><p>其中，<strong>大電流電源傳輸線</strong>是當前成長最快速的產品線。根據 2025 年法說會資料，AI 資料中心用大電流電源線（Hi-Amp 系列）營收比重已從五年前不到 10% 躍升至 2025 年的 36%，產品電流規格從 30A 提升至近 100A，單價與毛利率遠優於傳統電源線。此類產品主要用於 AI 伺服器機櫃的電源配電系統（PDU / Busway 連接），是資料中心電力基礎設施中的關鍵安全組件。</p><h2 id="二、技術壁壘與安規認證優勢" tabindex="-1">二、技術壁壘與安規認證優勢 <a class="header-anchor" href="#二、技術壁壘與安規認證優勢" aria-label="Permalink to &quot;二、技術壁壘與安規認證優勢&quot;">​</a></h2><p>良維最核心的競爭優勢來自其 <strong>50 年累積的安規認證護城河</strong>。電源線屬於安規管制產品，各國均有強制性安全標準，全球主要安規體系包括：</p><ul><li><strong>UL</strong>（美國）、<strong>JIS/PSE</strong>（日本）、<strong>CEE/CE</strong>（歐盟）</li><li><strong>SAA</strong>（澳洲）、<strong>BSI</strong>（英國）、<strong>CCC</strong>（中國）</li><li><strong>印度 BIS</strong>（近期取得，為印度擴產鋪路）</li></ul><p>良維累積了 <strong>33 國安規認證、近萬種部品組合</strong>，可在 229 個國家銷售其產品。這項資源意味著新進競爭者需要花費 3-5 年以上的時間與數千萬元的認證費用才能達到同等水準，形成極高的進入門檻。此外，公司早在 2004 年即領先同業開發出無鉛製程及無鹵電子線，並通過 DELL、HP 等國際大廠認證，在環保法規（RoHS/WEEE）的合規能力上同樣具備先發優勢。</p><h2 id="三、核心競爭力分析-swot-架構" tabindex="-1">三、核心競爭力分析（SWOT 架構） <a class="header-anchor" href="#三、核心競爭力分析-swot-架構" aria-label="Permalink to &quot;三、核心競爭力分析（SWOT 架構）&quot;">​</a></h2><h3 id="優勢-strengths" tabindex="-1">優勢 (Strengths) <a class="header-anchor" href="#優勢-strengths" aria-label="Permalink to &quot;優勢 (Strengths)&quot;">​</a></h3><ol><li><strong>安規護城河</strong>：33 國認證、50 年累積，競爭對手短期無法複製</li><li><strong>客戶關係黏性強</strong>：電源線一旦通過客戶認證（AVL），不易更換供應商</li><li><strong>財務體質優異</strong>：2025 年負債比僅 26.5%，流動性充裕，無短期借款壓力</li><li><strong>客戶分散化</strong>：同時服務 HP、Dell、Lenovo、Apple、Amazon、NVIDIA 等全球一線品牌</li><li><strong>產能彈性</strong>：台灣、中國、泰國、印度四地生產布局</li></ol><h3 id="弱勢-weaknesses" tabindex="-1">弱勢 (Weaknesses) <a class="header-anchor" href="#弱勢-weaknesses" aria-label="Permalink to &quot;弱勢 (Weaknesses)&quot;">​</a></h3><ol><li><strong>高速訊號線技術相對薄弱</strong>：公司坦言在高速訊號線領域競爭力不足，正尋求合作夥伴</li><li><strong>單一客戶集中風險</strong>：亞馬遜 AWS 曾占營收約 30%，雖有助於成長但也存在依賴風險</li><li><strong>銅價波動影響</strong>：電源線主要原料為銅，銅價波動對成本結構仍有影響（但大電流產品影響有限）</li></ol><h3 id="機會-opportunities" tabindex="-1">機會 (Opportunities) <a class="header-anchor" href="#機會-opportunities" aria-label="Permalink to &quot;機會 (Opportunities)&quot;">​</a></h3><ol><li><strong>AI 資料中心建設潮</strong>：2025-2030 年資料中心基礎建設 CAGR 高達 38%</li><li><strong>HVDC 高壓直流趨勢</strong>：800V 以上高壓直流架構成為新世代資料中心主流</li><li><strong>NVIDIA Vera Rubin 供應鏈</strong>：下半年出貨將帶動營運高峰</li><li><strong>伺服器內部線束</strong>：規劃切入內部線束，擴大產品組合深度</li><li><strong>全球產能擴張</strong>：泰國廠（一廠→二廠+新購土地）、印度廠同步擴建</li></ol><h3 id="威脅-threats" tabindex="-1">威脅 (Threats) <a class="header-anchor" href="#威脅-threats" aria-label="Permalink to &quot;威脅 (Threats)&quot;">​</a></h3><ol><li><strong>競爭對手追趕</strong>：貿聯-KY (3665)、佳必琪 (6197) 亦在 AI 大電流領域布局</li><li><strong>中國紅色供應鏈</strong>：雖受國安疑慮限制難以切入美系 CSP，但價格競爭壓力仍在</li><li><strong>中美貿易/地緣政治風險</strong>：產能分散至泰國、印度有助緩解，但政治局勢仍為變數</li><li><strong>技術迭代風險</strong>：若資料中心電源架構發生根本性改變，可能影響產品需求</li></ol><h2 id="四、競爭優勢量化驗證" tabindex="-1">四、競爭優勢量化驗證 <a class="header-anchor" href="#四、競爭優勢量化驗證" aria-label="Permalink to &quot;四、競爭優勢量化驗證&quot;">​</a></h2><h3 id="毛利率趨勢-反映定價能力與附加價值" tabindex="-1">毛利率趨勢（反映定價能力與附加價值） <a class="header-anchor" href="#毛利率趨勢-反映定價能力與附加價值" aria-label="Permalink to &quot;毛利率趨勢（反映定價能力與附加價值）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年度</th><th>毛利率</th><th>營業利益率</th><th>稅後淨利率</th></tr></thead><tbody><tr><td>2023</td><td>23.9%</td><td>8.2%</td><td>3.9%</td></tr><tr><td>2024</td><td>24.9%</td><td>11.9%</td><td>7.1%</td></tr><tr><td>2025</td><td>31.4%</td><td>17.9%</td><td>10.7%</td></tr></tbody></table><p>（數據來源：FinMind finance，作者自行計算：每月營收加總/逐季財報加總）</p><p>毛利率從 2023 年的 23.9% 持續攀升至 2025 年的 31.4%，營業利益率從 8.2% 翻倍至 17.9%，明確反映 AI 大電流高毛利產品佔比提升對整體獲利結構的優化效果。</p><h3 id="營收成長動能-yoy" tabindex="-1">營收成長動能（YoY） <a class="header-anchor" href="#營收成長動能-yoy" aria-label="Permalink to &quot;營收成長動能（YoY）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年度</th><th>合併營收</th><th>年增率</th><th>EPS</th><th>年增率</th></tr></thead><tbody><tr><td>2023</td><td>73.6 億</td><td>-</td><td>4.15</td><td>-</td></tr><tr><td>2024</td><td>80.4 億</td><td>+9.3%</td><td>6.42</td><td>+54.7%</td></tr><tr><td>2025</td><td>101.5 億</td><td>+26.3%</td><td>8.72</td><td>+35.8%</td></tr></tbody></table><p>營收與 EPS 均呈現加速成長態勢，2025 年營收突破百億大關，創歷史新高。</p><h2 id="五、投資價值評估與競爭態勢總結" tabindex="-1">五、投資價值評估與競爭態勢總結 <a class="header-anchor" href="#五、投資價值評估與競爭態勢總結" aria-label="Permalink to &quot;五、投資價值評估與競爭態勢總結&quot;">​</a></h2><p>良維的核心投資邏輯建立在其 <strong>「安規認證 × 客戶關係 × AI 資料中心成長紅利」</strong> 三重疊加之上。公司擁有全球電源線產業中最完整的安規認證組合，此護城河使其在面對中國同業的低價競爭時具備顯著的防禦力；而 AI 資料中心對電力傳輸品質與可靠度的極高要求，更進一步將良維的競爭門檻抬高。</p><p>從競爭格局來看：</p><ul><li>在 <strong>AI 伺服器大電流電源線</strong>領域，全球具備量產能力的廠商有限，良維是 AWS 的主力供應商，亦切入 NVIDIA Vera Rubin 供應鏈</li><li>在 <strong>傳統消費電子電源線</strong>領域，良維以 TV 電源線 40% 的全球市佔率維持龍頭地位</li><li>國內主要競爭者為貿聯-KY (3665)，在高速訊號線領域具有優勢</li><li>國際競爭者如安費諾（Amphenol）為傳統連接器大廠，但在電源線領域非其主攻方向</li></ul><p>綜合而言，良維的核心產品結構正從低毛利的消費性電子電源線向高毛利的 AI 伺服器大電流電源線轉型，此轉型已通過營收成長、毛利率擴張、EPS 躍升等財務指標獲得充分驗證。管理層預期泰國廠與印度廠新產能將在 2026 年持續放量，大電流產品佔比將進一步提升，為未來 2-3 年的獲利成長提供明確能見度。</p><hr><p><strong>數據來源</strong>：FinMind (finance, revenue, per, balance_sheet)、玉山證券個股頁面、自由財經、MoneyDJ 理財網、鉅亨網、vocus 方格子研究筆記、工商時報 <strong>檔案大小</strong>：5,218 bytes <strong>寫入時間</strong>：2026-04-24 05:29</p>',36)])])}const u=r(n,[["render",d]]);export{b as __pageData,u as default};
